package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import java.lang.foreign.MemorySegment;

import org.apache.datasketches.common.SketchesArgumentException;

/** Heap update OmniSketch. */
public final class UpdateOmniSketch extends OmniSketch {
	private final int lgWidth;
	private final int numRows;
	private final int nominalEntries;
	private final long seed;
	private final OmniSketchCell[][] cells;
	private long totalUpdates;

	UpdateOmniSketch(final int lgWidth, final int numRows, final int nominalEntries, final long seed) {
		this.lgWidth = lgWidth;
		this.numRows = numRows;
		this.nominalEntries = nominalEntries;
		this.seed = seed;
		this.cells = new OmniSketchCell[numRows][1 << lgWidth];
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < cells[row].length; column++) {
				cells[row][column] = new OmniSketchCell(nominalEntries);
			}
		}
	}

	/** Creates a new builder. */
	public static OmniSketchBuilder builder() {
		return OmniSketch.builder();
	}

	/** Updates this sketch with a value and a long identifier. */
	public void update(final Object value, final long identifier) {
		updateHash(OmniSketchHash.hashValue(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a value and an arbitrary identifier object. */
	public void update(final Object value, final Object identifier) {
		updateHash(OmniSketchHash.hashValue(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a long value and a long identifier. */
	public void update(final long value, final long identifier) {
		updateHash(OmniSketchHash.hashLong(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a double value and a long identifier. */
	public void update(final double value, final long identifier) {
		updateHash(OmniSketchHash.hashDouble(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a string value and a long identifier. */
	public void update(final String value, final long identifier) {
		updateHash(OmniSketchHash.hashValue(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a byte-array value and a long identifier. */
	public void update(final byte[] value, final long identifier) {
		updateHash(OmniSketchHash.hashValue(value, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with a null value and a long identifier. */
	public void updateNull(final long identifier) {
		updateHash(OmniSketchHash.hashValue(null, seed), OmniSketchHash.hashIdentifier(identifier, seed));
	}

	/** Updates this sketch with pre-hashed value and identifier hashes. */
	public void updateHash(final long valueHash, final long identifierHash) {
		for (int row = 0; row < numRows; row++) {
			final int column = OmniSketchHash.indexFor(OmniSketchHash.rowHash(valueHash, row, seed), lgWidth);
			cells[row][column].update(identifierHash);
		}
		totalUpdates++;
	}

	/** Alias for {@link #updateHash(long, long)}. */
	public void updatePreHashed(final long valueHash, final long identifierHash) {
		updateHash(valueHash, identifierHash);
	}

	/** Merges another compatible OmniSketch into this sketch. */
	public void merge(final OmniSketch other) {
		checkCompatible(other);
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < getWidth(); column++) {
				cells[row][column].merge(other.getCell(row, column));
			}
		}
		totalUpdates += other.getTotalUpdates();
	}

	/** Removes all retained data and returns this sketch to the empty state. */
	public void reset() {
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < getWidth(); column++) {
				cells[row][column] = new OmniSketchCell(nominalEntries);
			}
		}
		totalUpdates = 0L;
	}

	@Override
	public int getLgWidth() {
		return lgWidth;
	}

	@Override
	public int getNumRows() {
		return numRows;
	}

	@Override
	public int getNominalEntries() {
		return nominalEntries;
	}

	@Override
	public long getSeed() {
		return seed;
	}

	@Override
	public long getTotalUpdates() {
		return totalUpdates;
	}

	@Override
	public int getRetainedEntries() {
		int retained = 0;
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < getWidth(); column++) {
				retained += cells[row][column].getRetainedEntries();
			}
		}
		return retained;
	}

	@Override
	public boolean isEmpty() {
		return totalUpdates == 0L;
	}

	@Override
	public boolean isCompact() {
		return false;
	}

	@Override
	public int getCurrentBytes() {
		return getCompactBytes();
	}

	@Override
	public int getCompactBytes() {
		return OmniSketchSerializationUtil.getSerializedSize(this);
	}

	@Override
	public OmniSketchEstimate estimate(final OmniSketchPredicate predicate) {
		return summary(predicate).asEstimate();
	}

	@Override
	public CompactOmniSketch compact() {
		final OmniSketchCell[][] compactCells = new OmniSketchCell[numRows][getWidth()];
		for (int row = 0; row < numRows; row++) {
			for (int column = 0; column < getWidth(); column++) {
				compactCells[row][column] = cells[row][column].compactCopy();
			}
		}
		return new HeapCompactOmniSketch(lgWidth, numRows, nominalEntries, seed, totalUpdates, getRetainedEntries(),
				compactCells);
	}

	@Override
	public CompactOmniSketch compact(final MemorySegment dstSeg) {
		if (dstSeg == null) {
			return compact();
		}
		final int bytes = getCompactBytes();
		if (dstSeg.byteSize() < bytes) {
			throw new SketchesArgumentException("Destination MemorySegment is too small for compact OmniSketch: "
					+ dstSeg.byteSize() + " < " + bytes);
		}
		OmniSketchSerializationUtil.writeSketch(this, dstSeg, true);
		return CompactOmniSketch.wrap(dstSeg.asSlice(0, bytes));
	}

	@Override
	public byte[] toByteArray() {
		return OmniSketchSerializationUtil.toByteArray(this);
	}

	@Override
	OmniSketchCell getCell(final int row, final int column) {
		return cells[row][column];
	}

	@Override
	public String toString() {
		return "UpdateOmniSketch{" + "lgWidth=" + lgWidth + ", numRows=" + numRows + ", nominalEntries="
				+ nominalEntries + ", totalUpdates=" + totalUpdates + ", retainedEntries=" + getRetainedEntries() + '}';
	}
}
